namespace InventoryApp.Models;

public class Equipment
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<Equipment>> GetEquipmentAsync()
    {
        // Simulate network/database delay
        await Task.Delay(500);

        return new List<Equipment>
        {
            new() { Id = 1, Name = "Forklift A", Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B", Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 20) },
            new() { Id = 3, Name = "Hydraulic Press", Location = "Shop Floor", LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "CNC Mill #7", Location = "Machine Shop", LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 5, Name = "Air Compressor", Location = "Utility Room", LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 6, Name = "Pallet Jack C", Location = "Loading Dock", LastInspected = new DateTime(2026, 2, 28) },
            new() { Id = 7, Name = "Welding Station 3", Location = "Fabrication Bay", LastInspected = new DateTime(2026, 4, 8) },
            new() { Id = 8, Name = "Overhead Crane", Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 22) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Equipment>? equipment;
    private PersistingComponentStateSubscription _subscription;

    protected override async Task OnInitializedAsync()
    {
        // Try to restore data persisted from prerender; if found, skip the service call.
        if (!ApplicationState.TryTakeFromJson<List<Equipment>>("equipment", out var restored))
        {
            equipment = await EquipmentSvc.GetEquipmentAsync();
        }
        else
        {
            equipment = restored;
        }

        // Register callback to persist data when prerender completes,
        // so the interactive circuit can pick it up without a second fetch.
        _subscription = ApplicationState.RegisterOnPersisting(() =>
        {
            ApplicationState.PersistAsJson("equipment", equipment);
            return Task.CompletedTask;
        });
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

